namespace sv_8726e06723594f91ace0e0b7a24827bc.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public class ThemeService
{
    public ThemeMode Mode { get; private set; } = ThemeMode.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    public void SetMode(ThemeMode mode)
    {
        if (Mode == mode) return;
        Mode = mode;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChange?.Invoke();
    }

    public void SetTheme(ThemeMode mode, string accentColor)
    {
        var changed = Mode != mode || AccentColor != accentColor;
        Mode = mode;
        AccentColor = accentColor;
        if (changed) OnChange?.Invoke();
    }
}

@rendermode InteractiveServer
@inject ThemeService Theme
@implements IDisposable

<span class="theme-indicator" title="Current theme">
    @GetThemeIcon() @Theme.Mode
    <span class="accent-swatch" style="background-color: @Theme.AccentColor;"></span>
</span>

@code {
    protected override void OnInitialized()
    {
        Theme.OnChange += OnThemeChanged;
    }

    private void OnThemeChanged() => InvokeAsync(StateHasChanged);

    private string GetThemeIcon() => Theme.Mode switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark => "🌙",
        _ => "💻"
    };

    public void Dispose()
    {
        Theme.OnChange -= OnThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService Theme
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 500px;">
    <h4>Theme</h4>
    <div class="btn-group mb-3" role="group">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <button class="btn @(Theme.Mode == mode ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => Theme.SetMode(mode)">
                @mode
            </button>
        }
    </div>

    <h4>Accent Color</h4>
    <div class="d-flex align-items-center gap-3 mb-3">
        <input type="color" value="@Theme.AccentColor"
               @onchange="OnAccentChanged" class="form-control form-control-color" />
        <span>@Theme.AccentColor</span>
    </div>

    <div class="alert alert-info mt-3">
        Current: <strong>@Theme.Mode</strong> mode,
        accent <span style="color: @Theme.AccentColor;">■</span> @Theme.AccentColor
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        Theme.OnChange += OnThemeChanged;
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        Theme.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    private void OnThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        Theme.OnChange -= OnThemeChanged;
    }
}

